import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"7. KDS（キッチンディスプレイ）","description":"","frontmatter":{},"headers":[],"relativePath":"internal/features/07-kds.md","filePath":"internal/features/07-kds.md"}'),l={name:"internal/features/07-kds.md"};function i(h,t,o,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_7-kds-キッチンディスプレイ" tabindex="-1">7. KDS（キッチンディスプレイ） <a class="header-anchor" href="#_7-kds-キッチンディスプレイ" aria-label="Permalink to &quot;7. KDS（キッチンディスプレイ）&quot;">​</a></h1><p>KDS（Kitchen Display System）は、キッチンスタッフが注文をリアルタイムで確認し、調理の進捗を管理するための画面です。<code>/kds/</code> のURLで新しいタブとして開きます。</p><p>管理ダッシュボードのヘッダーにある「KDS」リンクをクリックするか、ブラウザで直接 <code>/kds/</code> にアクセスします。</p><h2 id="_7-1-初回起動" tabindex="-1">7.1 初回起動 <a class="header-anchor" href="#_7-1-初回起動" aria-label="Permalink to &quot;7.1 初回起動&quot;">​</a></h2><h3 id="起動手順" tabindex="-1">起動手順 <a class="header-anchor" href="#起動手順" aria-label="Permalink to &quot;起動手順&quot;">​</a></h3><ol><li>KDS画面にアクセスすると、認証チェックが行われます</li><li>複数店舗に所属している場合、店舗選択オーバーレイが表示されます <ul><li>初回のみ表示。選択した店舗はブラウザに記憶されます（localStorage キー：<code>mt_kds_store</code>）</li></ul></li><li><strong>音声起動オーバーレイ</strong>が表示されます <ul><li>「タップして開始」ボタンが表示されます</li><li>このタップでブラウザの音声再生が許可されます（Web Audio APIのunlock）</li><li>タップしないと効果音やビープ音が鳴りません</li></ul></li><li>KDS画面が表示され、注文のポーリング（3秒間隔）が開始されます</li></ol><div class="warning custom-block"><p class="custom-block-title">音声起動について</p><p>ブラウザのセキュリティ制限により、ユーザーの操作（タップ/クリック）なしに音声を再生することはできません。KDS起動時の「タップして開始」は音声機能を有効にするために必要です。この手順をスキップすると、新規注文の通知音やアラート音が鳴りません。</p></div><hr><h2 id="_7-2-画面構成" tabindex="-1">7.2 画面構成 <a class="header-anchor" href="#_7-2-画面構成" aria-label="Permalink to &quot;7.2 画面構成&quot;">​</a></h2><h3 id="_3カラムのカンバンボード" tabindex="-1">3カラムのカンバンボード <a class="header-anchor" href="#_3カラムのカンバンボード" aria-label="Permalink to &quot;3カラムのカンバンボード&quot;">​</a></h3><p>KDS画面は3つのカラム（列）で構成されています。注文カードは左から右へ進みます。</p><table tabindex="0"><thead><tr><th>カラム</th><th>名称</th><th>内容</th></tr></thead><tbody><tr><td>左</td><td>受付</td><td>新しく受け付けた注文（pending）</td></tr><tr><td>中央</td><td>調理中</td><td>調理を開始した注文（preparing）</td></tr><tr><td>右</td><td>提供待ち</td><td>調理が完了して提供を待っている注文（ready）</td></tr></tbody></table><p>各カラムが空の場合は「なし」と表示されます。</p><h3 id="ステーションバー" tabindex="-1">ステーションバー <a class="header-anchor" href="#ステーションバー" aria-label="Permalink to &quot;ステーションバー&quot;">​</a></h3><p>画面上部にステーション選択バーが表示されます。</p><table tabindex="0"><thead><tr><th>ボタン</th><th>説明</th></tr></thead><tbody><tr><td>全品目</td><td>全てのカテゴリの注文を表示（デフォルト）</td></tr><tr><td>[ステーション名]</td><td>そのステーションに割り当てられたカテゴリの品目のみ表示</td></tr></tbody></table><p><strong>ステーションの例：</strong></p><ul><li>「厨房」ステーション → メイン料理・前菜カテゴリを担当</li><li>「ドリンク」ステーション → ドリンクカテゴリを担当</li><li>「デザート」ステーション → デザートカテゴリを担当</li></ul><p>選択中のステーションはブラウザに記憶されます（localStorage キー：<code>mt_kds_station</code>）。</p><div class="tip custom-block"><p class="custom-block-title">ステーションの設定</p><p>KDSステーションは管理ダッシュボードの「店舗設定」→「KDSステーション」サブタブで設定します。ステーションごとに担当カテゴリを割り当てることで、キッチンの各セクションが自分の担当品目だけを見られるようになります。詳しくは「12. 店舗設定」の章を参照してください。</p></div><h3 id="コースフェーズバー" tabindex="-1">コースフェーズバー <a class="header-anchor" href="#コースフェーズバー" aria-label="Permalink to &quot;コースフェーズバー&quot;">​</a></h3><p>コース料理の注文がある場合、ステーションバーの下にコースフェーズバーが表示されます。</p><table tabindex="0"><thead><tr><th>表示要素</th><th>説明</th></tr></thead><tbody><tr><td>テーブルコード</td><td>コース注文のテーブル名</td></tr><tr><td>コース名</td><td>コース料理の名前</td></tr><tr><td>現在フェーズ</td><td>現在のフェーズ番号</td></tr><tr><td>「次フェーズ」ボタン</td><td>次のフェーズに進める</td></tr></tbody></table><p>コース注文がない場合、このバーは表示されません。</p><hr><h2 id="_7-3-注文カードの表示" tabindex="-1">7.3 注文カードの表示 <a class="header-anchor" href="#_7-3-注文カードの表示" aria-label="Permalink to &quot;7.3 注文カードの表示&quot;">​</a></h2><h3 id="カードの構成" tabindex="-1">カードの構成 <a class="header-anchor" href="#カードの構成" aria-label="Permalink to &quot;カードの構成&quot;">​</a></h3><p>各注文は以下の要素で構成されたカードとして表示されます。</p><p><strong>ヘッダー部分：</strong></p><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>テーブルコード</td><td>「5番」「A-1」など。テイクアウトの場合は顧客名</td></tr><tr><td>テイクアウトバッジ</td><td>テイクアウト注文の場合「テイクアウト」バッジ（青色）</td></tr><tr><td>受取時間</td><td>テイクアウトの場合、受取予定時刻（「18:30」）</td></tr><tr><td>コースバッジ</td><td>コース注文の場合「コース P1:前菜」形式（フェーズ番号＋フェーズ名）</td></tr><tr><td>経過時間</td><td>注文からの経過時間（「12m 34s」形式）</td></tr></tbody></table><p><strong>本文部分：</strong></p><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>メモ</td><td>注文メモがある場合に表示（「ネギ抜き」等）</td></tr><tr><td>アレルゲン警告</td><td>「⚠️ アレルギー: 卵, 乳, 小麦」形式で表示</td></tr><tr><td>品目リスト</td><td>品名 × 数量。オプションがある場合は小文字で表示</td></tr></tbody></table><p><strong>フッター部分：</strong></p><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>合計金額</td><td>注文合計（コース注文の場合は非表示）</td></tr><tr><td>アクションボタン</td><td>注文全体のステータス変更ボタン</td></tr><tr><td>取消ボタン</td><td>注文をキャンセル</td></tr></tbody></table><h3 id="経過時間と色の変化" tabindex="-1">経過時間と色の変化 <a class="header-anchor" href="#経過時間と色の変化" aria-label="Permalink to &quot;経過時間と色の変化&quot;">​</a></h3><p>注文カードは経過時間に応じて色が変わります。</p><table tabindex="0"><thead><tr><th>経過時間</th><th>カードの状態</th><th>意味</th></tr></thead><tbody><tr><td>10分未満</td><td>通常表示</td><td>正常範囲</td></tr><tr><td>10分以上</td><td>黄色背景（warning）</td><td>やや遅延</td></tr><tr><td>20分以上</td><td>赤色背景（danger）</td><td>大幅遅延</td></tr></tbody></table><h3 id="品目ごとのステータス表示" tabindex="-1">品目ごとのステータス表示 <a class="header-anchor" href="#品目ごとのステータス表示" aria-label="Permalink to &quot;品目ごとのステータス表示&quot;">​</a></h3><p>各品目には個別のステータスと操作ボタンが表示されます。</p><table tabindex="0"><thead><tr><th>品目ステータス</th><th>表示</th><th>アクションボタン</th></tr></thead><tbody><tr><td>pending</td><td>品名と数量</td><td>「調理開始」ボタン</td></tr><tr><td>preparing</td><td>品名と数量</td><td>「完成」ボタン</td></tr><tr><td>ready</td><td>品名と数量</td><td>「提供済」ボタン</td></tr><tr><td>served</td><td>取り消し線 + 「✓提供済」バッジ</td><td>—</td></tr><tr><td>cancelled</td><td>取り消し線 + 「❌」バッジ</td><td>—</td></tr></tbody></table><hr><h2 id="_7-4-注文の操作" tabindex="-1">7.4 注文の操作 <a class="header-anchor" href="#_7-4-注文の操作" aria-label="Permalink to &quot;7.4 注文の操作&quot;">​</a></h2><h3 id="注文全体の操作-カードレベル" tabindex="-1">注文全体の操作（カードレベル） <a class="header-anchor" href="#注文全体の操作-カードレベル" aria-label="Permalink to &quot;注文全体の操作（カードレベル）&quot;">​</a></h3><p>カードのフッターにあるボタンで、注文の全品目を一括操作できます。</p><table tabindex="0"><thead><tr><th>ボタン</th><th>動作</th><th>表示条件</th></tr></thead><tbody><tr><td>全品調理開始</td><td>全品目を pending → preparing に変更</td><td>注文ステータスが pending</td></tr><tr><td>全品完成</td><td>全品目を preparing → ready に変更</td><td>注文ステータスが preparing</td></tr><tr><td>全品提供済み</td><td>全品目を ready → served に変更</td><td>注文ステータスが ready</td></tr><tr><td>取消</td><td>注文をキャンセル</td><td>常時表示</td></tr></tbody></table><p><strong>注文キャンセル：</strong></p><ol><li>「取消」ボタンをクリックします</li><li>確認ダイアログが表示されます</li><li>「OK」をクリックすると注文ステータスが「cancelled」に変更されます</li><li>カードがKDSから消えます</li></ol><h3 id="品目個別の操作-アイテムレベル" tabindex="-1">品目個別の操作（アイテムレベル） <a class="header-anchor" href="#品目個別の操作-アイテムレベル" aria-label="Permalink to &quot;品目個別の操作（アイテムレベル）&quot;">​</a></h3><p>各品目の横にあるボタンで、品目ごとに個別操作できます。</p><table tabindex="0"><thead><tr><th>ボタン</th><th>動作</th></tr></thead><tbody><tr><td>調理開始</td><td>その品目だけを pending → preparing に変更</td></tr><tr><td>完成</td><td>その品目だけを preparing → ready に変更</td></tr><tr><td>提供済</td><td>その品目だけを ready → served に変更</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">個別操作と全体操作の使い分け</p><ul><li>1つの注文に複数品目がある場合、品目ごとに異なるタイミングで調理が進むことがあります</li><li>例：ドリンクは先に完成、メイン料理は後から完成</li><li>このような場合は品目個別の操作ボタンを使います</li><li>全品目が同時に進む場合はカードレベルのボタンが効率的です</li></ul></div><h3 id="楽観的更新-optimistic-update" tabindex="-1">楽観的更新（Optimistic Update） <a class="header-anchor" href="#楽観的更新-optimistic-update" aria-label="Permalink to &quot;楽観的更新（Optimistic Update）&quot;">​</a></h3><p>KDSではUI更新を高速化するため、楽観的更新パターンを使用しています。</p><ol><li>ボタンをクリックすると、サーバーからのレスポンスを待たずにUIが即座に更新されます</li><li>バックグラウンドでAPIリクエストが送信されます</li><li>APIリクエストが成功すれば、そのまま表示が維持されます</li><li>APIリクエストが失敗した場合、次のポーリング（3秒後）で正しい状態に修正されます</li></ol><hr><h2 id="_7-5-コース料理の操作" tabindex="-1">7.5 コース料理の操作 <a class="header-anchor" href="#_7-5-コース料理の操作" aria-label="Permalink to &quot;7.5 コース料理の操作&quot;">​</a></h2><h3 id="コースフェーズの進行" tabindex="-1">コースフェーズの進行 <a class="header-anchor" href="#コースフェーズの進行" aria-label="Permalink to &quot;コースフェーズの進行&quot;">​</a></h3><p>コース料理の注文は、フェーズ（段階）ごとに料理が提供されます。</p><p><strong>フェーズの進め方：</strong></p><ol><li>コースフェーズバーの対象テーブルの「次フェーズ」ボタンをクリックします</li><li>確認メッセージが表示されます：「現フェーズの未完了品目は全て提供済みになります」</li><li>「OK」をクリックすると以下が実行されます <ul><li>現在のフェーズの未完了品目が全て「served」に変更されます</li><li>フェーズ番号が1つ進みます（例：フェーズ1 → フェーズ2）</li><li>次のフェーズの品目が自動的にKDSに表示されます</li></ul></li></ol><p><strong>コース注文の表示上の特徴：</strong></p><ul><li>カードの左ボーダーが緑色（3px）</li><li>コースバッジ（「コース P1:前菜」形式）がヘッダーに表示</li><li>合計金額は表示されません（コース料理は一括料金のため）</li></ul><hr><h2 id="_7-6-リアルタイム更新" tabindex="-1">7.6 リアルタイム更新 <a class="header-anchor" href="#_7-6-リアルタイム更新" aria-label="Permalink to &quot;7.6 リアルタイム更新&quot;">​</a></h2><h3 id="ポーリング" tabindex="-1">ポーリング <a class="header-anchor" href="#ポーリング" aria-label="Permalink to &quot;ポーリング&quot;">​</a></h3><p>KDSは定期的にサーバーから最新の注文データを取得します。</p><table tabindex="0"><thead><tr><th>状態</th><th>ポーリング間隔</th></tr></thead><tbody><tr><td>通常時</td><td>3秒</td></tr><tr><td>オフライン時</td><td>30秒</td></tr><tr><td>接続復旧時</td><td>即座に3秒に復帰＋強制リフレッシュ</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">ポーリング方式について</p><p>POSLAはWebSocketやServer-Sent Eventsではなく、HTTPポーリング方式を採用しています。3秒間隔で十分なリアルタイム性を実現しつつ、サーバー構成をシンプルに保っています。</p></div><h3 id="オフライン検知" tabindex="-1">オフライン検知 <a class="header-anchor" href="#オフライン検知" aria-label="Permalink to &quot;オフライン検知&quot;">​</a></h3><p>インターネット接続が切断された場合：</p><ul><li>ポーリング間隔が30秒に延長されます</li><li>画面上にオフライン警告が表示されます</li><li>接続が復旧すると自動的に通常のポーリングに戻ります</li></ul><hr><h2 id="_7-7-スタッフ呼び出しアラート" tabindex="-1">7.7 スタッフ呼び出しアラート <a class="header-anchor" href="#_7-7-スタッフ呼び出しアラート" aria-label="Permalink to &quot;7.7 スタッフ呼び出しアラート&quot;">​</a></h2><p>お客さんがセルフオーダー画面からスタッフを呼び出すと、KDS画面にアラートが表示されます。</p><h3 id="アラートの表示" tabindex="-1">アラートの表示 <a class="header-anchor" href="#アラートの表示" aria-label="Permalink to &quot;アラートの表示&quot;">​</a></h3><ul><li>画面上部に赤色のバナーとして表示されます</li><li>5秒ごとにチェックされます</li><li>アラート1件ごとに以下が表示されます</li></ul><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>🔔アイコン</td><td>ベルアイコン</td></tr><tr><td>テーブルコード</td><td>呼び出し元のテーブル</td></tr><tr><td>呼び出し理由</td><td>お客さんが入力した理由（「お水ください」等）</td></tr><tr><td>経過時間</td><td>呼び出しからの経過時間</td></tr><tr><td>「対応済み」ボタン</td><td>アラートを消す</td></tr></tbody></table><h3 id="効果音" tabindex="-1">効果音 <a class="header-anchor" href="#効果音" aria-label="Permalink to &quot;効果音&quot;">​</a></h3><p>新しいアラートが検知されると効果音が鳴ります。</p><ul><li><strong>ビープ音パターン：</strong> 880Hz → 1100Hz（2音）</li><li><strong>音量：</strong> 30%</li><li><strong>使用API：</strong> Web Audio API（サイン波）</li></ul><div class="info custom-block"><p class="custom-block-title">KDSでのアラートフィルタリング</p><p>KDS画面では「staff_call」（スタッフ呼び出し）タイプのアラートのみが表示されます。「product_ready」（料理完成通知）や「kitchen_call」（キッチン内連絡）はKDSには表示されません（これらはハンディPOS画面に表示されます）。</p></div><hr><h2 id="_7-8-ai音声コマンド" tabindex="-1">7.8 AI音声コマンド <a class="header-anchor" href="#_7-8-ai音声コマンド" aria-label="Permalink to &quot;7.8 AI音声コマンド&quot;">​</a></h2><p>KDSはWeb Speech APIを使用した音声コマンドに対応しています（Chrome推奨）。</p><h3 id="音声コマンドの起動" tabindex="-1">音声コマンドの起動 <a class="header-anchor" href="#音声コマンドの起動" aria-label="Permalink to &quot;音声コマンドの起動&quot;">​</a></h3><ol><li>KDS起動時の「タップして開始」で音声機能が有効化されます</li><li>ブラウザのマイクアクセス許可が求められる場合があります</li><li>音声認識は日本語モードで動作します</li></ol><h3 id="対応コマンド" tabindex="-1">対応コマンド <a class="header-anchor" href="#対応コマンド" aria-label="Permalink to &quot;対応コマンド&quot;">​</a></h3><p>音声で注文のステータスを変更できます。具体的なコマンド体系は音声コマンダーモジュール（voice-commander.js）で定義されており、テーブル番号や品目名の音声認識による操作が可能です。</p><div class="warning custom-block"><p class="custom-block-title">Chrome推奨</p><p>Web Speech APIの continuous モード（連続認識）はGoogle Chromeでのみ安定動作します。Firefox、Safari、Edgeでは音声コマンド機能が使えない場合があります。</p></div><hr><h2 id="_7-9-aiキッチンダッシュボード" tabindex="-1">7.9 AIキッチンダッシュボード <a class="header-anchor" href="#_7-9-aiキッチンダッシュボード" aria-label="Permalink to &quot;7.9 AIキッチンダッシュボード&quot;">​</a></h2><p>KDS画面にはAIによる調理優先度の提案機能があります。</p><h3 id="パネルの表示" tabindex="-1">パネルの表示 <a class="header-anchor" href="#パネルの表示" aria-label="Permalink to &quot;パネルの表示&quot;">​</a></h3><ul><li>画面下部からスライドアップするパネル（画面の40%の高さ）</li><li>パネルを開くとAI分析が開始されます</li><li><strong>60秒ごとに自動更新</strong>されます</li><li>手動リフレッシュボタンもあります</li></ul><h3 id="aiの分析内容" tabindex="-1">AIの分析内容 <a class="header-anchor" href="#aiの分析内容" aria-label="Permalink to &quot;AIの分析内容&quot;">​</a></h3><p>AIは現在のpending（受付）とpreparing（調理中）の注文を分析し、3つのカテゴリに分類します。</p><table tabindex="0"><thead><tr><th>カテゴリ</th><th>色</th><th>意味</th></tr></thead><tbody><tr><td>⚡ 今すぐ着手</td><td>赤色</td><td>最優先で調理すべき品目</td></tr><tr><td>🔜 次に着手</td><td>オレンジ色</td><td>次に調理を開始すべき品目</td></tr><tr><td>⏸ 待機中</td><td>グレー</td><td>まだ着手不要な品目</td></tr></tbody></table><h3 id="aiからの追加情報" tabindex="-1">AIからの追加情報 <a class="header-anchor" href="#aiからの追加情報" aria-label="Permalink to &quot;AIからの追加情報&quot;">​</a></h3><table tabindex="0"><thead><tr><th>情報</th><th>説明</th></tr></thead><tbody><tr><td>ペースステータス</td><td>良好 / 通常 / 混雑</td></tr><tr><td>サマリーコメント</td><td>AIによる状況の要約（日本語）</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">AI分析のAPI</p><p>AIキッチンダッシュボードはGemini APIを使用して分析を行います。APIキーはPOSLA運営が一括管理しているため、テナント側での設定は不要です。</p></div><hr><h2 id="_7-10-kdsステーションの設定" tabindex="-1">7.10 KDSステーションの設定 <a class="header-anchor" href="#_7-10-kdsステーションの設定" aria-label="Permalink to &quot;7.10 KDSステーションの設定&quot;">​</a></h2><p>KDSステーションは管理ダッシュボードの「店舗設定」→「KDSステーション」サブタブで管理します。</p><h3 id="ステーションの追加" tabindex="-1">ステーションの追加 <a class="header-anchor" href="#ステーションの追加" aria-label="Permalink to &quot;ステーションの追加&quot;">​</a></h3><ol><li>「KDSステーション」サブタブを開きます</li><li>「ステーション追加」ボタンをクリックします</li><li>以下を入力します</li></ol><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>ステーション名</td><td>日本語名（例：「厨房」「ドリンクバー」）</td></tr><tr><td>ステーション名（英語）</td><td>英語名（例：「Kitchen」「Drink Bar」）</td></tr><tr><td>担当カテゴリ</td><td>チェックボックスで複数選択。そのステーションが担当するメニューカテゴリ</td></tr></tbody></table><ol start="4"><li>「保存」ボタンをクリックします</li></ol><h3 id="ステーションの編集・削除" tabindex="-1">ステーションの編集・削除 <a class="header-anchor" href="#ステーションの編集・削除" aria-label="Permalink to &quot;ステーションの編集・削除&quot;">​</a></h3><ul><li>編集：ステーション名やカテゴリ割り当てを変更</li><li>有効/無効の切替：無効にするとKDSのステーションバーに表示されなくなります</li><li>削除：ステーションを完全に削除</li></ul><h3 id="ステーション運用の例" tabindex="-1">ステーション運用の例 <a class="header-anchor" href="#ステーション運用の例" aria-label="Permalink to &quot;ステーション運用の例&quot;">​</a></h3><p><strong>大規模キッチンの場合：</strong></p><table tabindex="0"><thead><tr><th>ステーション名</th><th>担当カテゴリ</th><th>KDSタブレット配置場所</th></tr></thead><tbody><tr><td>厨房（メイン）</td><td>メイン料理、前菜、サラダ</td><td>メイン調理場</td></tr><tr><td>揚げ場</td><td>揚げ物</td><td>フライヤー横</td></tr><tr><td>ドリンク</td><td>ドリンク、デザート</td><td>ドリンクバー</td></tr></tbody></table><p>各タブレットでKDSを開き、該当するステーションを選択すると、そのセクション担当の品目だけが表示されます。</p><p><strong>小規模キッチンの場合：</strong></p><p>ステーション設定をせず「全品目」のまま使用すれば、全ての注文が1つの画面に表示されます。</p>',115)])])}const u=d(l,[["render",i]]);export{p as __pageData,u as default};
